import{_ as s,o as i,c as n,a2 as e}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"问题发现中的 JTBD、当前工作流与替代方案","description":"","frontmatter":{},"headers":[],"relativePath":"02-product/notes/02-problem-evidence/13-jtbd-current-workflow-alternatives.md","filePath":"02-product/notes/02-problem-evidence/13-jtbd-current-workflow-alternatives.md","lastUpdated":null}'),l={name:"02-product/notes/02-problem-evidence/13-jtbd-current-workflow-alternatives.md"};function t(r,a,p,h,d,o){return i(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="问题发现中的-jtbd、当前工作流与替代方案" tabindex="-1">问题发现中的 JTBD、当前工作流与替代方案 <a class="header-anchor" href="#问题发现中的-jtbd、当前工作流与替代方案" aria-label="Permalink to &quot;问题发现中的 JTBD、当前工作流与替代方案&quot;">​</a></h1><p>JTBD 用于描述人在特定情境中想取得的进展；当前工作流说明这个结果现在如何通过人员、工具和规则实现；替代方案说明用户实际可以选择的其他路径。三者必须联合：JTBD 约束结果，工作流提供事实，替代方案揭示选择与切换成本。</p><h2 id="一、jtbd-不是用户画像或功能需求" tabindex="-1">一、JTBD 不是用户画像或功能需求 <a class="header-anchor" href="#一、jtbd-不是用户画像或功能需求" aria-label="Permalink to &quot;一、JTBD 不是用户画像或功能需求&quot;">​</a></h2><p>Christensen Institute 将 JTBD 描述为理解情境与驱动力如何推动人和组织作出选择的视角。产品研究中可以把它写成：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当 [触发与约束] 出现时，</span></span>
<span class="line"><span>[承担任务的角色] 想要 [完成可验证的进展]，</span></span>
<span class="line"><span>以便 [取得更高层结果]，</span></span>
<span class="line"><span>同时避免 [不可接受的风险或损失]。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>示例：</p><blockquote><p>当月末需要核对多个账户且原始数据持续变化时，财务负责人想形成可追溯的差异清单，以便在关账前修正异常，同时避免覆盖原始记录。</p></blockquote><p>它不写“想要一个 AI 对账按钮”。按钮是方案；差异清单和可追溯关账才是结果。</p><p>JTBD 也不等于人口属性。年龄、行业和公司规模只有在改变触发、约束、风险或工作流时才进入分析。</p><h2 id="二、拆解任务层级" tabindex="-1">二、拆解任务层级 <a class="header-anchor" href="#二、拆解任务层级" aria-label="Permalink to &quot;二、拆解任务层级&quot;">​</a></h2><p>同一个陈述可能过宽或过窄：</p><table tabindex="0"><thead><tr><th>层级</th><th>示例</th><th>用途</th></tr></thead><tbody><tr><td>高层进展</td><td>完成月度财务关账</td><td>确定完整结果</td></tr><tr><td>核心任务</td><td>找出并解释账户差异</td><td>比较替代路径</td></tr><tr><td>子任务</td><td>导入流水、匹配记录、标记异常</td><td>观察工作流</td></tr><tr><td>操作</td><td>点击上传、选择日期</td><td>设计交互</td></tr></tbody></table><p>若把操作当 JTBD，产品变化后任务会失效；若只写“经营得更好”，又无法验证。合适粒度通常能定义触发、产物、完成与失败，并允许多种方案竞争。</p><h2 id="三、从证据构建-而不是凭空编写" tabindex="-1">三、从证据构建，而不是凭空编写 <a class="header-anchor" href="#三、从证据构建-而不是凭空编写" aria-label="Permalink to &quot;三、从证据构建，而不是凭空编写&quot;">​</a></h2><p>GOV.UK 指南建议同时了解谁在使用服务、想做什么、当前如何完成、遇到什么问题，以及需要什么结果；已有分析、搜索日志、支持数据和过去研究都可以作为证据，用户访谈不是唯一入口。</p><p>个人学习者可使用：</p><ul><li>真实任务日志和产物；</li><li>当前流程观察；</li><li>帮助文档、FAQ 和已知限制；</li><li>Issue、公开社区和评论中的触发与后果；</li><li>行为数据中的开始、完成、回退和放弃；</li><li>非软件方案的实际执行记录。</li></ul><p>每个 JTBD 元素链接证据：触发可能来自日历与任务日志，结果来自下游产物，风险来自错误记录，替代来自实际工具。没有证据的部分标为假设。</p><h2 id="四、还原当前工作流" tabindex="-1">四、还原当前工作流 <a class="header-anchor" href="#四、还原当前工作流" aria-label="Permalink to &quot;四、还原当前工作流&quot;">​</a></h2><p>工作流从真实触发到结果，不从产品首页到产品成功页。记录：</p><ol><li>触发事件与责任人；</li><li>每一步角色、工具、输入和输出；</li><li>主动处理、等待和交接；</li><li>规则、权限和审批；</li><li>错误、返工和变通；</li><li>最终产物与下游使用；</li><li>放弃或不行动的结果。</li></ol><p>正式 SOP 与实际动作分开。使用消息补材料、把数据复制到私人表格或等待某位专家，可能揭示工具边界，也可能带来合规风险。</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;job_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;JOB-RECON-01&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;trigger&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;月末第一个工作日&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;actor&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;财务负责人&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;desired_progress&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;形成已解释且可追溯的差异清单&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;completion&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;所有重大差异有证据、负责人和状态&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;current_workflow_version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-07-v1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;evidence&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;task-log-18&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;artifact-diff-07&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;assumptions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;小额差异可自动忽略的阈值尚未验证&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="五、替代方案的完整集合" tabindex="-1">五、替代方案的完整集合 <a class="header-anchor" href="#五、替代方案的完整集合" aria-label="Permalink to &quot;五、替代方案的完整集合&quot;">​</a></h2><h3 id="直接软件替代" tabindex="-1">直接软件替代 <a class="header-anchor" href="#直接软件替代" aria-label="Permalink to &quot;直接软件替代&quot;">​</a></h3><p>相近产品以相近机制完成任务。比较结果、恢复、权限和总成本，不按功能数量排名。</p><h3 id="间接工具与组合方案" tabindex="-1">间接工具与组合方案 <a class="header-anchor" href="#间接工具与组合方案" aria-label="Permalink to &quot;间接工具与组合方案&quot;">​</a></h3><p>表格 + 消息 + 脚本 + 人工复核可能比单一产品更真实。组合方案的优势常是可控、可修改和已被组织批准。</p><h3 id="人工与专业服务" tabindex="-1">人工与专业服务 <a class="header-anchor" href="#人工与专业服务" aria-label="Permalink to &quot;人工与专业服务&quot;">​</a></h3><p>人工处理成本随任务增长，但在低频、高风险或例外多的场景可能更合适。</p><h3 id="推迟、不做与改变目标" tabindex="-1">推迟、不做与改变目标 <a class="header-anchor" href="#推迟、不做与改变目标" aria-label="Permalink to &quot;推迟、不做与改变目标&quot;">​</a></h3><p>用户可能接受差异、降低精度、延后关账或取消任务。若不行动成本低，软件机会也可能很弱。</p><h3 id="自建与继续维护" tabindex="-1">自建与继续维护 <a class="header-anchor" href="#自建与继续维护" aria-label="Permalink to &quot;自建与继续维护&quot;">​</a></h3><p>已有脚本或内部流程有维护成本，也有数据控制、定制和沉没学习。不能只比较订阅价格。</p><h2 id="六、替代方案的选择力量" tabindex="-1">六、替代方案的选择力量 <a class="header-anchor" href="#六、替代方案的选择力量" aria-label="Permalink to &quot;六、替代方案的选择力量&quot;">​</a></h2><p>选择不只由效率决定。记录：</p><ul><li>现状推力：什么后果让人考虑改变；</li><li>新方案拉力：预期得到什么；</li><li>现状习惯：熟悉度、数据、审批和团队默契；</li><li>新方案焦虑：迁移、隐私、可靠性、锁定和失败；</li><li>触发事件：价格变化、事故、人员离开或新规则。</li></ul><p>“现有表格步骤多”不表示会迁移。如果表格透明、可审计且团队熟悉，其净价值可能仍高于新工具。</p><h2 id="七、计算切换的净收益" tabindex="-1">七、计算切换的净收益 <a class="header-anchor" href="#七、计算切换的净收益" aria-label="Permalink to &quot;七、计算切换的净收益&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>净收益 = 目标结果改善</span></span>
<span class="line"><span>       - 学习与配置成本</span></span>
<span class="line"><span>       - 数据迁移与双轨成本</span></span>
<span class="line"><span>       - 新的运营和供应商风险</span></span>
<span class="line"><span>       - 退出与锁定成本</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>不同成本需统一任务和时间窗。一次节省 5 分钟但每月只发生一次，可能不足以覆盖迁移；低频但避免重大数据损失，则不能只看时间。</p><h2 id="八、事实、推断与请求" tabindex="-1">八、事实、推断与请求 <a class="header-anchor" href="#八、事实、推断与请求" aria-label="Permalink to &quot;八、事实、推断与请求&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事实：本月三次对账都把两个系统导出的CSV复制到同一表格。</span></span>
<span class="line"><span>事实：其中一次因列顺序变化导致公式引用错误。</span></span>
<span class="line"><span>推断：当前工作流对输入格式变化敏感。</span></span>
<span class="line"><span>用户请求：希望增加自动导入。</span></span>
<span class="line"><span>需求表达：需要在输入格式变化时仍能发现并安全处理差异。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>自动导入可能解决复制成本，也可能把错误静默放大。需求应保留结果和风险，使规则校验、映射、人工确认或文档改进都能参与比较。</p><h2 id="八点一、区分任务承担者、决策者和受益者" tabindex="-1">八点一、区分任务承担者、决策者和受益者 <a class="header-anchor" href="#八点一、区分任务承担者、决策者和受益者" aria-label="Permalink to &quot;八点一、区分任务承担者、决策者和受益者&quot;">​</a></h2><p>组织任务常由不同角色共同完成：财务专员执行对账，负责人批准差异，审计人员使用证据，采购决定工具。只记录采购请求会漏掉执行成本，只记录操作者又会漏掉风险责任。</p><p>为每个角色写：触发、动作、结果、承担的失败后果和对方案的否决条件。角色目标冲突也是事实，例如执行者希望少填字段，审计者需要完整来源。产品机会不是选择某一方偏好，而是找到满足任务结果与必要控制的路径。</p><h3 id="任务的稳定部分与变化部分" tabindex="-1">任务的稳定部分与变化部分 <a class="header-anchor" href="#任务的稳定部分与变化部分" aria-label="Permalink to &quot;任务的稳定部分与变化部分&quot;">​</a></h3><p>高层结果可能稳定，具体工作流会随工具和政策变化。证据卡分别版本化：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>稳定任务：在关账前解释重大差异并保留审计证据</span></span>
<span class="line"><span>当前工作流 v1：CSV + 表格公式 + 邮件审批</span></span>
<span class="line"><span>当前工作流 v2：数据仓库 + 规则匹配 + 工单审批</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果触发、责任或完成结果也变化，应新建任务版本，不把新工作流硬套旧 JTBD。方案上线后重新观察实际流程，因为用户可能新增变通，且旧步骤不一定自动消失。</p><h3 id="证据不足时的表达" tabindex="-1">证据不足时的表达 <a class="header-anchor" href="#证据不足时的表达" aria-label="Permalink to &quot;证据不足时的表达&quot;">​</a></h3><p>只有公开请求时，可以写“有人请求自动排会”，不能补出其触发和结果。先建立问题假设和证据缺口，使用公开任务文档、真实替代执行或行为结果验证。为了让模板完整而虚构情境，会让后续方案建立在不可追溯的前提上。</p><h2 id="九、完整案例-五人跨时区排会" tabindex="-1">九、完整案例：五人跨时区排会 <a class="header-anchor" href="#九、完整案例-五人跨时区排会" aria-label="Permalink to &quot;九、完整案例：五人跨时区排会&quot;">​</a></h2><h3 id="_1-初始请求" tabindex="-1">1. 初始请求 <a class="header-anchor" href="#_1-初始请求" aria-label="Permalink to &quot;1. 初始请求&quot;">​</a></h3><p>观察到的解决请求是“做一个自动找共同空闲时间的功能”。先不接受该方案，重建任务。</p><h3 id="_2-证据输入" tabindex="-1">2. 证据输入 <a class="header-anchor" href="#_2-证据输入" aria-label="Permalink to &quot;2. 证据输入&quot;">​</a></h3><p>教学场景包括 12 次真实排会日志、日历事件、邮件线程和公开预约工具文档：</p><ul><li>触发：项目进入需要同步决策的阶段；</li><li>角色：项目负责人对会议成立负责；</li><li>完成：五人收到时区正确、无已知冲突且包含议程的事件；</li><li>当前路径：群消息询问 → 表格收集 → 人工比较 → 创建事件；</li><li>12 次中 4 次有人迟回复，3 次确认后改期；</li><li>主动协调中位 18 分钟，总历时中位 26 小时；</li><li>2 次会议最终改为异步文档，不再需要排会。</li></ul><h3 id="_3-jtbd" tabindex="-1">3. JTBD <a class="header-anchor" href="#_3-jtbd" aria-label="Permalink to &quot;3. JTBD&quot;">​</a></h3><blockquote><p>当跨时区成员需要对一个不能异步解决的决策同步时，项目负责人想在截止日期前得到所有必要参与者确认的可行时间，以便完成决策，同时避免暴露无关日历信息和反复改期。</p></blockquote><p>“不能异步解决”是需要验证的约束，不是默认事实。</p><h3 id="_4-当前工作流" tabindex="-1">4. 当前工作流 <a class="header-anchor" href="#_4-当前工作流" aria-label="Permalink to &quot;4. 当前工作流&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>负责人发起并给候选范围</span></span>
<span class="line"><span>→ 参与者分别回复偏好</span></span>
<span class="line"><span>→ 负责人人工合并时区和忙闲</span></span>
<span class="line"><span>→ 缺回复时提醒</span></span>
<span class="line"><span>→ 建立事件与议程</span></span>
<span class="line"><span>→ 冲突后重新收集</span></span>
<span class="line"><span>→ 五人确认</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>主要损失位于等待和改期，不只是寻找空闲时间。议程缺失也可能造成会议成立但任务失败。</p><h3 id="_5-替代方案" tabindex="-1">5. 替代方案 <a class="header-anchor" href="#_5-替代方案" aria-label="Permalink to &quot;5. 替代方案&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方案</th><th>结果覆盖</th><th>优势</th><th>成本与风险</th></tr></thead><tbody><tr><td>自动日历匹配</td><td>找共同时间</td><td>主动时间低</td><td>需授权日历，跨组织限制</td></tr><tr><td>候选投票</td><td>收集偏好</td><td>无需完整日历权限</td><td>仍需等待与改期</td></tr><tr><td>主持人指定</td><td>快速建立事件</td><td>步骤少</td><td>冲突与参与公平性</td></tr><tr><td>人工表格</td><td>全面可控</td><td>熟悉、透明</td><td>等待与重复劳动</td></tr><tr><td>异步文档</td><td>避免会议</td><td>无排期</td><td>争议可能不收敛</td></tr><tr><td>不做</td><td>无协调成本</td><td>适合低价值议题</td><td>决策延期或缺失</td></tr></tbody></table><h3 id="_6-推理结论" tabindex="-1">6. 推理结论 <a class="header-anchor" href="#_6-推理结论" aria-label="Permalink to &quot;6. 推理结论&quot;">​</a></h3><p><strong>事实</strong>：当前样本的等待远高于主动时间，且部分任务可由异步方案完成。</p><p><strong>推断</strong>：把所有日历自动匹配并非完整机会；先判断是否需要同步，再为真正会议减少收集和改期，可能更接近目标。</p><p><strong>假设</strong>：明确议题是否需要同步、设置回复截止与自动失效候选，能减少总历时；需用新任务验证。</p><h3 id="_7-验证" tabindex="-1">7. 验证 <a class="header-anchor" href="#_7-验证" aria-label="Permalink to &quot;7. 验证&quot;">​</a></h3><ol><li>对未来 6 次任务先做同步必要性检查；</li><li>其中符合会议条件的任务采用候选投票；</li><li>分别记录主动时间、总历时、改期和隐私授权；</li><li>检查事件是否含议程并最终完成决策；</li><li>与旧路径和异步方案比较同一完成标准；</li><li>保留成员拒绝授权、未回复和临时取消的失败分支。</li></ol><h3 id="_8-失败分支" tabindex="-1">8. 失败分支 <a class="header-anchor" href="#_8-失败分支" aria-label="Permalink to &quot;8. 失败分支&quot;">​</a></h3><ul><li>若参与者不愿共享日历，自动匹配方案不满足风险边界；</li><li>若异步文档未能形成决策，不能用“没有会议”当成功；</li><li>若指定时段很快但关键成员缺席，结果不合格；</li><li>若只有负责人的任务日志，结论限定组织者视角；</li><li>若低频任务的迁移成本高于节省，保留现状可能合理。</li></ul><h2 id="十、验证三者是否一致" tabindex="-1">十、验证三者是否一致 <a class="header-anchor" href="#十、验证三者是否一致" aria-label="Permalink to &quot;十、验证三者是否一致&quot;">​</a></h2><p>检查：JTBD 的每个结果是否在工作流中有产物；工作流问题是否影响该结果；替代方案是否完成相同边界；不行动是否被考虑；切换成本是否来自证据。</p><p>如果“更高效”没有单位、基线和结果，它不是可验证进展。如果方案只能完成子任务，应说明剩余工作由谁承担。</p><h2 id="十一、个人学习路径" tabindex="-1">十一、个人学习路径 <a class="header-anchor" href="#十一、个人学习路径" aria-label="Permalink to &quot;十一、个人学习路径&quot;">​</a></h2><ol><li>选择一个自己每月真实执行的任务；</li><li>保存三次当前工作流与产物；</li><li>从触发、结果和风险写 JTBD；</li><li>去掉产品名和特定界面；</li><li>实际执行一个软件、一个人工和一个不做/延后替代；</li><li>比较完成、时间、控制、恢复和切换；</li><li>将事实、推断和方案请求分开。</li></ol><p>不需要先进行用户访谈，但自我样本不能外推其他角色。</p><h2 id="十二、完成检查与练习" tabindex="-1">十二、完成检查与练习 <a class="header-anchor" href="#十二、完成检查与练习" aria-label="Permalink to &quot;十二、完成检查与练习&quot;">​</a></h2><ul><li>JTBD 有触发、进展、结果和风险边界；</li><li>工作流来自真实任务而非理想制度；</li><li>从端到端结果而非产品入口开始；</li><li>包含软件、组合工具、人工、推迟和不做；</li><li>记录现状优势而不只列缺点；</li><li>切换成本与净收益可复核；</li><li>请求与需求结果分开；</li><li>案例有反证和失败分支；</li><li>结论限定角色、场景和证据。</li></ul><p>练习：完成一个 JTBD—工作流—替代三联分析，实际执行至少三种替代。完成标准是任何指定产品被移除后，任务仍可理解并能比较结果。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.christenseninstitute.org/theory/jobs-to-be-done/" target="_blank" rel="noreferrer">Christensen Institute：Jobs to Be Done Theory</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/user-research/start-by-learning-user-needs" target="_blank" rel="noreferrer">GOV.UK Service Manual：Learning about users and their needs</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/design/map-a-users-whole-problem" target="_blank" rel="noreferrer">GOV.UK Service Manual：Map and understand a user&#39;s whole problem</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/user-research/contextual-research-and-observation" target="_blank" rel="noreferrer">GOV.UK Service Manual：Contextual research and observation</a>（访问日期：2026-07-17）</li></ul>`,86)])])}const b=s(l,[["render",t]]);export{c as __pageData,b as default};
